.cs-dash {
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  overflow: hidden;
}

.cs-dash__tabs {
  display: flex;
  border-bottom: 1px solid #e5e7eb;
  background: #f9fafb;
}

.cs-dash__tab {
  flex: 1;
  padding: 0.625rem 1rem;
  border: none;
  background: transparent;
  font-size: 0.875rem;
  font-weight: 500;
  color: #6b7280;
  cursor: pointer;
  border-bottom: 2px solid transparent;
  position: relative;
}

.cs-dash__tab:hover {
  color: #374151;
}

.cs-dash__tab--active {
  color: #3b82f6;
  border-bottom-color: #3b82f6;
}

.cs-dash__badge {
  position: absolute;
  top: 0.25rem;
  right: 0.25rem;
  width: 0.5rem;
  height: 0.5rem;
  background: #10b981;
  border-radius: 50%;
}

.cs-dash__content {
  padding: 1.5rem;
  min-height: 12rem;
}

.panel h2 {
  margin: 0 0 1rem;
  font-size: 1.125rem;
}

.panel__grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.75rem;
}

.panel__card {
  padding: 1rem;
  background: #f9fafb;
  border-radius: 0.375rem;
  font-size: 0.875rem;
}

.panel__form {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.panel__reports {
  list-style: none;
  padding: 0;
  margin: 0;
}

.panel__reports li {
  padding: 0.5rem 0;
  border-bottom: 1px solid #f3f4f6;
  font-size: 0.875rem;
}

.loading-skeleton {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.loading-skeleton__bar {
  height: 1rem;
  background: #e5e7eb;
  border-radius: 0.25rem;
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

.error-fallback {
  text-align: center;
  padding: 2rem;
}

.error-fallback__title {
  font-size: 1rem;
  font-weight: 600;
  color: #ef4444;
  margin-bottom: 0.5rem;
}

.error-fallback__btn {
  padding: 0.375rem 0.75rem;
  border: none;
  border-radius: 0.375rem;
  background: #3b82f6;
  color: white;
  cursor: pointer;
  font-size: 0.8125rem;
}

