import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Code Splitting Dashboard', () => {
  it('renders tab buttons', () => {
    render(<App />);
    expect(screen.getByTestId('panel-tab-analytics')).toBeInTheDocument();
    expect(screen.getByTestId('panel-tab-settings')).toBeInTheDocument();
    expect(screen.getByTestId('panel-tab-reports')).toBeInTheDocument();
  });

  it('first tab is active by default', () => {
    render(<App />);
    expect(screen.getByTestId('panel-tab-analytics')).toHaveClass('cs-dash__tab--active');
  });

  it('shows loading fallback during lazy load', async () => {
    render(<App />);
    // The loading fallback should appear briefly or the content should resolve
    await waitFor(() => {
      const content = screen.getByTestId('panel-content');
      expect(content).toBeInTheDocument();
    });
  });

  it('loads panel content after lazy import resolves', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('panel-content')).toBeInTheDocument();
    });
  });

  it('switching tabs updates active class', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('panel-tab-settings'));
    expect(screen.getByTestId('panel-tab-settings')).toHaveClass('cs-dash__tab--active');
  });

  it('switching tabs loads new panel content', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('panel-tab-settings'));
    await waitFor(() => {
      const content = screen.getByTestId('panel-content');
      expect(content).toBeInTheDocument();
    });
  });
});

