import React, { useState, Suspense, Component, ReactNode, lazy } from 'react';
import './styles.css';

interface Tab {
  id: string;
  label: string;
}

const tabs: Tab[] = [
  { id: 'analytics', label: 'Analytics' },
  { id: 'settings', label: 'Settings' },
  { id: 'reports', label: 'Reports' },
];

// Lazy imports
const importMap: Record<string, () => Promise<{ default: React.ComponentType }>> = {
  analytics: () => import('./Analytics'),
  settings: () => import('./Settings'),
  reports: () => import('./Reports'),
};

const lazyMap: Record<string, React.LazyExoticComponent<React.ComponentType>> = {
  analytics: lazy(importMap.analytics),
  settings: lazy(importMap.settings),
  reports: lazy(importMap.reports),
};

// Loading Fallback
const LoadingFallback: React.FC = () => (
  <div data-testid="loading-fallback" className="loading-skeleton">
    <div className="loading-skeleton__bar" style={{ width: '40%' }} />
    <div className="loading-skeleton__bar" style={{ width: '100%' }} />
    <div className="loading-skeleton__bar" style={{ width: '80%' }} />
    <div className="loading-skeleton__bar" style={{ width: '60%' }} />
  </div>
);

// Error Boundary
interface EBProps { children: ReactNode; onRetry: () => void; }
interface EBState { hasError: boolean; }

class ErrorBoundary extends Component<EBProps, EBState> {
  state: EBState = { hasError: false };
  static getDerivedStateFromError(): EBState { return { hasError: true }; }
  componentDidCatch() {}
  handleRetry = () => {
    this.setState({ hasError: false });
    this.props.onRetry();
  };
  render() {
    if (this.state.hasError) {
      return (
        <div data-testid="error-boundary" className="error-fallback">
          <p className="error-fallback__title">Failed to load panel</p>
          <button data-testid="retry-btn" className="error-fallback__btn" onClick={this.handleRetry}>
            Retry
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

export const Dashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState('analytics');
  const [loadedPanels, setLoadedPanels] = useState<Set<string>>(new Set());
  const [retryKey, setRetryKey] = useState(0);

  const handlePreload = (id: string) => {
    importMap[id]?.().then(() => {
      setLoadedPanels(prev => new Set(prev).add(id));
    }).catch(() => {});
  };

  const PanelComponent = lazyMap[activeTab];

  return (
    <div className="cs-dash">
      <div className="cs-dash__tabs">
        {tabs.map(tab => (
          <button
            key={tab.id}
            data-testid={`panel-tab-${tab.id}`}
            className={`cs-dash__tab${tab.id === activeTab ? ' cs-dash__tab--active' : ''}`}
            onClick={() => setActiveTab(tab.id)}
            onMouseEnter={() => handlePreload(tab.id)}
          >
            {tab.label}
            {loadedPanels.has(tab.id) && <span data-testid={`loaded-${tab.id}`} className="cs-dash__badge" />}
          </button>
        ))}
      </div>
      <div className="cs-dash__content">
        <ErrorBoundary key={retryKey} onRetry={() => setRetryKey(k => k + 1)}>
          <Suspense fallback={<LoadingFallback />}>
            <PanelComponent />
          </Suspense>
        </ErrorBoundary>
      </div>
    </div>
  );
};
